// Detectar tipo de entrada: PDF, Excel, Imagen o Texto
const item = $input.first();
const binaryData = item.binary || {};
const binaryKeys = Object.keys(binaryData);

let fileType = 'text';
let mimeType = '';
let fileName = '';
let binaryKey = null;

if (binaryKeys.length > 0) {
  binaryKey = binaryKeys[0];
  const binEntry = binaryData[binaryKey];
  mimeType = binEntry.mimeType || '';
  fileName = binEntry.fileName || binEntry.fileExtension || '';
  const nameLower = fileName.toLowerCase();

  if (mimeType.includes('pdf') || nameLower.endsWith('.pdf')) {
    fileType = 'pdf';
  } else if (
    mimeType.includes('spreadsheet') ||
    mimeType.includes('excel') ||
    mimeType.includes('csv') ||
    nameLower.endsWith('.xlsx') ||
    nameLower.endsWith('.xls') ||
    nameLower.endsWith('.csv')
  ) {
    fileType = 'excel';
  } else if (
    mimeType.startsWith('image/') ||
    nameLower.match(/\.(jpg|jpeg|png|gif|bmp|webp|tiff)$/)
  ) {
    fileType = 'image';
  } else {
    // Otros documentos (Word, txt, etc.) → tratar como doc
    fileType = 'doc';
  }
}

return [{
  json: {
    ...item.json,
    fileType,
    mimeType,
    fileName,
    binaryKey,
    hasFile: binaryKeys.length > 0
  },
  binary: item.binary
}];

// Preparar imagen en base64 para Claude Vision
const item = $input.first();
const binaryKey = item.json.binaryKey || Object.keys(item.binary || {})[0];
const bin = item.binary[binaryKey];

return [{
  json: {
    imageBase64: bin.data,
    imageMimeType: bin.mimeType || 'image/jpeg',
    fileType: 'image'
  }
}];

// Normalizar salida del PDF
const item = $input.first();
const text = item.json.text || item.json.content || JSON.stringify(item.json);
return [{ json: { extractedContent: text.trim(), sourceType: 'PDF' } }];

// Normalizar salida del Excel/CSV
const items = $input.all();
const rows = items.map(i => i.json);
const text = JSON.stringify(rows, null, 2);
return [{ json: { extractedContent: text, sourceType: 'Excel/CSV' } }];

// Normalizar respuesta de Claude Vision
const item = $input.first();
const content = item.json?.content?.[0]?.text
  || (Array.isArray(item.json?.content) ? item.json.content.map(c => c.text || '').join('\n') : '')
  || item.json?.content
  || '';
return [{ json: { extractedContent: content.trim(), sourceType: 'Imagen' } }];

// Normalizar texto libre o documento sin formato especial
const item = $input.first();
const body = item.json;

// Intentar extraer el texto de múltiples fuentes posibles
const text =
  body.texto ||
  body.text ||
  body.contenido ||
  body.content ||
  body.data ||
  body.body?.texto ||
  body.body?.text ||
  body.query?.texto ||
  body.query?.text ||
  '';

return [{ json: { extractedContent: text.trim(), sourceType: 'Texto' } }];

// Parsear respuesta de Claude y generar HTML de la OC
const item = $input.first();

// Extraer texto de la respuesta de Claude
let rawText = '';
if (item.json?.content?.[0]?.text) {
  rawText = item.json.content[0].text;
} else if (item.json?.content) {
  rawText = Array.isArray(item.json.content)
    ? item.json.content.map(c => c.text || '').join('')
    : String(item.json.content);
}

// Parsear el JSON de la OC
let oc;
try {
  // Limpiar posibles bloques de código markdown
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  oc = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'No se pudo parsear la respuesta: ' + e.message,
      rawResponse: rawText
    }
  }];
}

// Formatear números
const fmt = (n) => {
  if (n == null) return '0';
  return new Intl.NumberFormat('es-CL').format(n);
};

// Generar HTML
const itemsHTML = (oc.items || []).map((item, i) => `
  <tr>
    <td>${item.linea || i + 1}</td>
    <td>${item.codigo || ''}</td>
    <td>${item.descripcion || ''}</td>
    <td style="text-align:center">${item.cantidad || 0}</td>
    <td style="text-align:center">${item.unidad || 'UN'}</td>
    <td style="text-align:right">${fmt(item.precioUnitario)}</td>
    <td style="text-align:center">${item.descuento || 0}%</td>
    <td style="text-align:right">${fmt(item.total)}</td>
  </tr>`).join('');

const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <title>Orden de Compra ${oc.numero || ''}</title>
  <style>
    * { box-sizing: border-box; }
    body { font-family: Arial, sans-serif; font-size: 12px; color: #333; margin: 20px; }
    .header { display: flex; justify-content: space-between; margin-bottom: 20px; }
    .title { font-size: 24px; font-weight: bold; color: #1a3a6b; }
    .oc-number { font-size: 18px; color: #1a3a6b; }
    .section { margin-bottom: 16px; }
    .section-title { font-size: 13px; font-weight: bold; background: #1a3a6b; color: white; padding: 4px 8px; margin-bottom: 8px; }
    .info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4px 16px; }
    .info-row { display: flex; gap: 6px; }
    .info-label { font-weight: bold; min-width: 120px; }
    table { width: 100%; border-collapse: collapse; }
    th { background: #1a3a6b; color: white; padding: 6px 8px; text-align: left; }
    td { padding: 5px 8px; border-bottom: 1px solid #ddd; }
    tr:nth-child(even) { background: #f5f7fa; }
    .totals { width: 300px; margin-left: auto; margin-top: 12px; }
    .totals td { padding: 4px 8px; }
    .totals .total-row { font-weight: bold; font-size: 14px; background: #1a3a6b; color: white; }
    .footer-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
    .badge { display: inline-block; background: #e8f0fe; color: #1a3a6b; padding: 2px 8px; border-radius: 4px; font-weight: bold; }
  </style>
</head>
<body>
  <div class="header">
    <div>
      <div class="title">ORDEN DE COMPRA</div>
      <div class="oc-number">${oc.numero || 'N/A'}</div>
      <div>Fecha: <strong>${oc.fecha || 'N/A'}</strong></div>
    </div>
    <div style="text-align:right">
      <div>Moneda: <span class="badge">${oc.moneda || 'CLP'}</span></div>
      ${oc.validezOferta ? `<div style="margin-top:4px">Validez: ${oc.validezOferta}</div>` : ''}
    </div>
  </div>

  <div style="display:grid; grid-template-columns:1fr 1fr; gap:16px">
    <div class="section">
      <div class="section-title">PROVEEDOR</div>
      <div class="info-grid">
        <div class="info-row"><span class="info-label">Nombre:</span> ${oc.proveedor?.nombre || 'N/A'}</div>
        <div class="info-row"><span class="info-label">RUT:</span> ${oc.proveedor?.rut || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Dirección:</span> ${oc.proveedor?.direccion || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Teléfono:</span> ${oc.proveedor?.telefono || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Email:</span> ${oc.proveedor?.email || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Contacto:</span> ${oc.proveedor?.contacto || 'N/A'}</div>
      </div>
    </div>
    <div class="section">
      <div class="section-title">COMPRADOR</div>
      <div class="info-grid">
        <div class="info-row"><span class="info-label">Empresa:</span> ${oc.comprador?.empresa || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Departamento:</span> ${oc.comprador?.departamento || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Solicitado por:</span> ${oc.comprador?.solicitadoPor || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Email:</span> ${oc.comprador?.email || 'N/A'}</div>
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">DETALLE DE PRODUCTOS / SERVICIOS</div>
    <table>
      <thead>
        <tr>
          <th>#</th>
          <th>Código</th>
          <th>Descripción</th>
          <th style="text-align:center">Cantidad</th>
          <th style="text-align:center">Unidad</th>
          <th style="text-align:right">Precio Unit.</th>
          <th style="text-align:center">Dcto.</th>
          <th style="text-align:right">Total</th>
        </tr>
      </thead>
      <tbody>${itemsHTML}</tbody>
    </table>
    <table class="totals">
      <tr><td>Subtotal:</td><td style="text-align:right">${fmt(oc.subtotal)} ${oc.moneda || 'CLP'}</td></tr>
      ${oc.descuentoTotal ? `<tr><td>Descuento:</td><td style="text-align:right">-${fmt(oc.descuentoTotal)} ${oc.moneda || 'CLP'}</td></tr>` : ''}
      <tr><td>IVA (${oc.porcentajeIva || 0}%):</td><td style="text-align:right">${fmt(oc.iva)} ${oc.moneda || 'CLP'}</td></tr>
      <tr class="total-row"><td>TOTAL:</td><td style="text-align:right">${fmt(oc.total)} ${oc.moneda || 'CLP'}</td></tr>
    </table>
  </div>

  <div class="footer-grid">
    <div class="section">
      <div class="section-title">CONDICIONES</div>
      <div class="info-grid">
        <div class="info-row"><span class="info-label">Pago:</span> ${oc.condicionesPago || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Entrega:</span> ${oc.tiempoEntrega || 'N/A'}</div>
        <div class="info-row"><span class="info-label">Lugar entrega:</span> ${oc.lugarEntrega || 'N/A'}</div>
      </div>
    </div>
    ${oc.notas ? `<div class="section"><div class="section-title">NOTAS</div><p>${oc.notas}</p></div>` : ''}
  </div>

  <div style="display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-top:40px">
    <div style="text-align:center;border-top:1px solid #333;padding-top:8px">Firma Solicitante</div>
    <div style="text-align:center;border-top:1px solid #333;padding-top:8px">Firma Autorización</div>
  </div>
</body>
</html>`;

return [{
  json: {
    success: true,
    ordenDeCompra: oc,
    htmlOrden: html
  }
}];
